    45	uint32_t nfapi_calculate_checksum(uint8_t *buffer, uint16_t len) {
    46	  uint32_t chksum = 0;
    47	  // calcaulte upto the checksum
    48	  chksum = crc32(chksum, buffer, 8);
    49	  // skip the checksum
    50	  uint8_t zeros[4] = {0, 0, 0, 0};
    51	  chksum = crc32(chksum, zeros, 4);
    52	  // continu with the rest of the mesage
    53	  chksum = crc32(chksum, &buffer[NFAPI_P7_HEADER_LENGTH], len - NFAPI_P7_HEADER_LENGTH);
    54	  // return the inverse
    55	  return ~(chksum);
    56	}
